#include <cstring>
#include <iostream>
using namespace std;
int main()
{
    char c[105] = {};
    char c1[105] = {};
    cin >> c;
    int len = strlen(c);
    for(int i = 0; i < len - 1; i++){
        c1[i] = c[i] + c[i + 1];
    }
    c1[len - 1] = c[0] + c[len - 1];
    cout << c1;
    return 0;
}
